CREATE VIEW `ads_finance_moneylog_month_report_mob_view` (`dt` COMMENT "账期(yyyyMM)", `dt_year` COMMENT "账期(yyyy)", `product_id` COMMENT "产品id", `pre_cost` COMMENT "阅币存点（期初）", `recharge` COMMENT "本月充值阅币,getmoneylog.realget", `cost` COMMENT "本月消耗阅币, usermoneylog.amount", `ad_cost` COMMENT "本月广告消耗阅币, ad_amount", `next_cost` COMMENT "阅币存点（期末）") AS SELECT `a`.`dt`, `a`.`dt_year`, `a`.`product_id`, ifnull(lag(`a`.`cash_surplus`, 1, 0E0) OVER (PARTITION BY `a`.`product_id` ORDER BY `a`.`dt` ASC ), 0) AS `pre_cost`, ifnull(`a`.`recharge`, 0) AS `recharge`, ifnull(`a`.`cost`, 0) AS `cost`, ifnull(`a`.`ad_cost`, 0) AS `ad_cost`, ifnull(`a`.`cash_surplus`, 0) AS `next_cost`
FROM (SELECT `a`.`dt`, `a`.`dt_year`, `a`.`product_id`, `a`.`recharge`, `a`.`cost`, `a`.`ad_cost`, sum(`a`.`month_cash_surplus`) OVER (PARTITION BY `a`.`product_id` ORDER BY `a`.`dt` ASC ) AS `cash_surplus`
FROM (SELECT date_format(`a`.`dt`, '%Y%m') AS `dt`, date_format(`a`.`dt`, '%Y') AS `dt_year`, `a`.`product_id`, sum(if(`a`.`report_type` = 1, `a`.`amount`, 0)) AS `recharge`, abs(sum(if((`a`.`report_type` = 2) AND (`a`.`book_id` != 0), `a`.`amount`, 0))) AS `cost`, abs(sum(if((`a`.`report_type` = 2) AND (`a`.`book_id` = 0), `a`.`amount`, 0))) AS `ad_cost`, (sum(if(`a`.`report_type` = 1, `a`.`amount`, 0))) + (sum(if(`a`.`report_type` = 2, `a`.`amount`, 0))) AS `month_cash_surplus`
FROM (SELECT `ads`.`ads_sr_finance_book_recharge_consume_info`.`dt`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`product_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`user_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`book_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`order_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`coo_order_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`shop_item_id`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`report_type`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`amount`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`remain_amount`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`remain_amount_all`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`cost`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`test_flag`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`order_time`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`expiration_time`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`duration_time`, `ads`.`ads_sr_finance_book_recharge_consume_info`.`etl_time`
FROM `ads`.`ads_sr_finance_book_recharge_consume_info` UNION ALL SELECT `ads`.`ads_sv_finance_series_recharge_consume_info`.`dt`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`product_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`user_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`series_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`order_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`coo_order_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`shop_item_id`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`report_type`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`amount`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`remain_amount`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`remain_amount_all`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`cost`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`test_flag`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`order_time`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`expiration_time`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`duration_time`, `ads`.`ads_sv_finance_series_recharge_consume_info`.`etl_time`
FROM `ads`.`ads_sv_finance_series_recharge_consume_info`) `a`
GROUP BY date_format(`a`.`dt`, '%Y%m'), date_format(`a`.`dt`, '%Y'), `a`.`product_id`) `a`) `a`;